- In this query, 'M' refers to the medium size; 
- Preference scores and satisfaction ratings are used as metrics to understand user preferences and satisfaction levels; 
- The unit of measurement is assumed to be the same for all clothing measurements (e.g., cm or inches).

sql:
SELECT AVG(preference_score) AS average_preference_score
FROM size_preferences
WHERE region_id = 1 AND demographic = '26-35';

SELECT size_label
FROM sizes
ORDER BY size_label;

SELECT COUNT(*) AS feedback_count
  FROM size_feedback
  WHERE size_id = (SELECT size_id FROM sizes WHERE size_label = 'S');

SELECT COUNT(*) AS change_count
FROM historical_sizes
WHERE change_date = '2023-01-01';

SELECT demographic
FROM size_preferences
WHERE region_id = 1 AND size_id = 1;

SELECT AVG(satisfaction_rating) AS average_satisfaction
FROM size_feedback
WHERE size_id = 0;

SELECT size_label
FROM sizes
WHERE updated_at = (SELECT MAX(updated_at) FROM sizes);

SELECT size_label
FROM sizes
WHERE size_id > 1;

SELECT COUNT(DISTINCT user_id) AS unique_user_count
FROM size_feedback
WHERE size_id = 0;
